local StructHeroCoreContent = LxClass("StructHeroCoreContent", nil)
function StructHeroCoreContent:StructHeroCoreContent()
	self.level = 0
	self.grade = 0

	self.fetters = {}
	self.fettersKey = {}

	self.useFetters = {}
	self.useFettersKey = {}

	self.element = {}
	self.elementRefIdToIndex = {}
	self.elementIndexToRefId = {}

	self.resetFetters = {}
	self.resetFettersKey = {}
end

function StructHeroCoreContent:CreateByPb(pb)
	self.level = pb.level			-- 等级表RefId
	self.grade = pb.grade			-- 阶级表refId

	self.fetters = {}
	self.fettersKey = {}
	local fetters = pb.fetters
	for i,v in ipairs(fetters) do
		table.insert(self.fetters,v)
		self.fettersKey[v] = v
	end

	self.useFetters = {}
	self.useFettersKey = {}
	local useFetters = pb.useFetters
	for i,v in ipairs(useFetters) do
		table.insert(self.useFetters,v)
		self.useFettersKey[v] = v
	end

	self.element = {}
	self.elementRefIdToIndex = {}
	self.elementIndexToRefId = {}
	local elementRefId,elementIndex
	local element = pb.element
	for i,v in ipairs(element) do
		elementRefId = v.refId
		elementIndex = v.index

		self.elementRefIdToIndex[elementRefId] = elementIndex
		self.elementIndexToRefId[elementIndex] = elementRefId
		table.insert(self.element,{
			index = elementIndex,
			refId = elementRefId,
		})
	end

	self.resetFetters = {}
	self.resetFettersKey = {}
	local resetFetters = pb.resetFetters
	for i,v in ipairs(resetFetters) do
		table.insert(self.resetFetters,v)
		self.resetFettersKey[v] = v
	end
end

return StructHeroCoreContent